  useSyncExternalStore,
} from "react";

import { createCheckedContext } from "@dfp/react-utils";

type Listener = () => void;

type SelectionStore = {
  getSnapshot: () => number | null;
  subscribe: (listener: Listener) => () => void;
  setSelectedColumn: (index: number | null) => void;
};

function createSelectionStore(): SelectionStore {
  let selectedColumn: number | null = null;
  const listeners = new Set<Listener>();

  return {
    getSnapshot: () => selectedColumn,
    subscribe: (listener) => {
      listeners.add(listener);
      return () => listeners.delete(listener);
    },
    setSelectedColumn: (index) => {
      if (index === selectedColumn) return;
      selectedColumn = index;
      listeners.forEach((listener) => listener());
    },
  };
}

const [SelectionStoreProvider, useStore] = createCheckedContext<SelectionStore>(
  "SelectionStoreContext",
);

/**
 * Hook for components that need the selected column value (header, chart).
 * Re-renders whenever the selected column changes.
 */
export function useSelectedColumn(): number | null {
  const store = useStore();
  return useSyncExternalStore(store.subscribe, store.getSnapshot);
}

/**
 * Optimized hook for cells — only re-renders when THIS column's highlight status changes.
 */
export function useIsColumnSelected(columnIndex: number): boolean {
  const store = useStore();
  return useSyncExternalStore(
    store.subscribe,
    () => store.getSnapshot() === columnIndex,
  );
}

type SelectionProviderProps = {
  children: ReactNode;
  selectedColumn: number | null;
};

/**
 * Provides column selection state to the tree.
 * Accepts the derived selectedColumn and pushes it into the external store
 * for optimized cell-level subscriptions.
 */
export function SelectionProvider({
  children,
  selectedColumn,
}: SelectionProviderProps) {
  const store = useMemo(() => createSelectionStore(), []);

  useLayoutEffect(() => {
    store.setSelectedColumn(selectedColumn);
  }, [store, selectedColumn]);

  return (
    <SelectionStoreProvider value={store}>{children}</SelectionStoreProvider>
  );
}

